mapper.update:
/* tms-master-store-sql-oracle.xml - updateTTMstStore */
UPDATE TT_MST_STORE
	SET ZIPCODE				= #{zipcode}
	  ,ADDRESS1				= #{address1}
	  ,ADDRESS2				= #{address2}

	  ,OWNER_NAME				= #{ownerName}
	  ,STORE_NAME				= #{storeName}
	  ,TEL1					= #{tel1}
	  ,SV_NM					= #{scNm}
	  ,REGNO					= #{regno}
	  ,CLOSEDATE				= #{closedate}
	  ,TEL2					= #{tel2}
	  ,ADDRID					= #{addrid}
	  ,DELYN 					= #{delyn}
	  ,CLOSDATE			= SUBSTR(#{closdate}, 0, 14)
	  ,CUST_TYPE			= #{custType}
	  ,CUST_TYPE_DETAIL   = #{custTypeDetail}

	,UPDATEDATE				= #{sysdate}
	,UPDATEURKEY			= #{surkey}
 WHERE 
 	STORE_KEY = #{storeKey}

mapper.select:
/* tms-master-store-sql-oracle.xml - selectPkCntTTMstStorexct */
SELECT COUNT(1)  
  FROM TT_MST_STORE
 WHERE CTKEY = #{ctkey}
   STORE_KEY = #{storeKey}

