UPDATE TT_MST_STOREXCT
SET   DELYN = 'N'
	, CLOSDATE = #{closdate}
	, UPDATEURKEY = #{surkey}
	, UPDATEDATE = #{sysdate}
WHERE CTKEY = #{ctkey}
AND   STORE_KEY = #{storeKey}

